#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.spectralArrow)]
    public class SpectralArrow : ProjectileBehaviour
    {
        public SpectralArrow(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void PostHitEntity(ProjectileHitOutput hitResult, DamageOutput? damage)
        {
            base.PostHitEntity(hitResult, damage);
            var arrow = hitResult.Projectile;
            var enemy = hitResult.Other;
            if (damage?.BodyResult == null && damage?.ArmorResult == null)
                return;
            enemy.InflictGlowing(150, new EntitySourceReference(arrow));
        }
    }
}
